import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { Document, DocumentStatus } from './types';
import DocumentForm from './components/DocumentForm';
import DocumentList from './components/DocumentList';
import { BriefcaseIcon, LogoIcon } from './components/icons';

const App: React.FC = () => {
  const [documents, setDocuments] = useState<Document[]>([]);

  useEffect(() => {
    // Load initial mock data
    setDocuments([
      {
        id: 'doc-1',
        title: 'รายงานสรุปผลการดำเนินงานไตรมาส 3',
        sender: 'ฝ่ายแผนงาน',
        recipient: 'ผู้บริหารระดับสูง',
        details: 'เอกสารสรุปผลการดำเนินงานประจำไตรมาสที่ 3 ของปีงบประมาณ พร้อมแนบไฟล์นำเสนอ',
        file: { name: 'Q3-Report.pdf', size: 1200000 },
        submittedAt: new Date(Date.now() - 86400000),
        status: DocumentStatus.Delivered,
      },
      {
        id: 'doc-2',
        title: 'ขออนุมัติโครงการพัฒนาระบบสารสนเทศ',
        sender: 'ฝ่ายเทคโนโลยีสารสนเทศ',
        recipient: 'ผู้บริหารระดับสูง',
        details: 'เอกสารขออนุมัติโครงการพัฒนาระบบสารสนเทศใหม่ เพื่อเพิ่มประสิทธิภาพการทำงาน',
        file: { name: 'IT-Project-Proposal.docx', size: 450000 },
        submittedAt: new Date(Date.now() - 3600000),
        status: DocumentStatus.InTransit,
      },
      {
        id: 'doc-3',
        title: 'แผนการตลาดผลิตภัณฑ์ใหม่',
        sender: 'ฝ่ายการตลาด',
        recipient: 'ผู้บริหารระดับสูง',
        details: 'นำเสนอแผนการตลาดสำหรับผลิตภัณฑ์ใหม่ที่จะเปิดตัวในไตรมาสหน้า',
        file: { name: 'New-Product-Marketing-Plan.pptx', size: 3200000 },
        submittedAt: new Date(),
        status: DocumentStatus.Pending,
      },
       {
        id: 'doc-4',
        title: 'รายงานการตรวจสอบภายใน',
        sender: 'ฝ่ายตรวจสอบ',
        recipient: 'ผู้บริหารระดับสูง',
        details: 'เอกสารรายงานผลการตรวจสอบภายในประจำปี ถูกตีกลับเนื่องจากข้อมูลไม่ครบถ้วน',
        file: { name: 'Internal-Audit-Report.pdf', size: 980000 },
        submittedAt: new Date(Date.now() - 172800000),
        status: DocumentStatus.Rejected,
      },
    ]);
  }, []);

  const addDocument = (doc: Omit<Document, 'id' | 'submittedAt' | 'status'>) => {
    const newDoc: Document = {
      ...doc,
      id: `doc-${Date.now()}`,
      submittedAt: new Date(),
      status: DocumentStatus.Pending,
    };

    // Add new document and simulate the delivery process
    setDocuments(prevDocs => [newDoc, ...prevDocs]);

    setTimeout(() => {
      setDocuments(prevDocs => 
        prevDocs.map(d => 
          d.id === newDoc.id ? { ...d, status: DocumentStatus.InTransit } : d
        )
      );
    }, 2000); // Simulate transit time
  };

  const updateDocumentStatus = (id: string, status: DocumentStatus) => {
    setDocuments(prevDocs =>
      prevDocs.map(doc => (doc.id === id ? { ...doc, status } : doc))
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800">
      <header className="bg-white shadow-sm sticky top-0 z-10">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <LogoIcon className="h-10 w-10 text-blue-600" />
            <div>
              <h1 className="text-xl md:text-2xl font-bold text-slate-800">ระบบส่งเอกสารภายใน</h1>
              <p className="text-sm text-slate-500">สำหรับ ผสน. และ ผบร.</p>
            </div>
          </div>
        </div>
      </header>

      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-1">
            <DocumentForm onSubmit={addDocument} />
          </div>
          <div className="lg:col-span-2">
            <div className="bg-white p-6 rounded-xl shadow-md">
              <div className="flex items-center gap-3 mb-6">
                <BriefcaseIcon className="h-7 w-7 text-blue-600" />
                <h2 className="text-2xl font-bold">รายการเอกสาร</h2>
              </div>
              <DocumentList documents={documents} onUpdateStatus={updateDocumentStatus} />
            </div>
          </div>
        </div>
      </main>

      <footer className="text-center py-6 mt-8 text-sm text-slate-500">
        <p>&copy; {new Date().getFullYear()} Document Delivery System. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default App;

export enum DocumentStatus {
  Pending = 'รอดำเนินการ',
  InTransit = 'กำลังนำส่ง',
  Delivered = 'ส่งแล้ว',
  Rejected = 'ตีกลับ',
}

export interface Document {
  id: string;
  title: string;
  sender: string;
  recipient: string;
  details: string;
  file: {
    name: string;
    size: number;
  };
  submittedAt: Date;
  status: DocumentStatus;
}

import React, { useState, FormEvent, useRef } from 'react';
import { Document } from '../types';
import { SendIcon, UploadCloudIcon, PaperclipIcon } from './icons';

interface DocumentFormProps {
  onSubmit: (doc: Omit<Document, 'id' | 'submittedAt' | 'status'>) => void;
}

const DocumentForm: React.FC<DocumentFormProps> = ({ onSubmit }) => {
  const [sender, setSender] = useState('');
  const [recipient, setRecipient] = useState('');
  const [title, setTitle] = useState('');
  const [details, setDetails] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    if (!sender || !recipient || !title || !details || !file) {
      alert('กรุณากรอกข้อมูลให้ครบถ้วนและแนบไฟล์');
      return;
    }

    onSubmit({
      sender,
      recipient,
      title,
      details,
      file: { name: file.name, size: file.size },
    });

    // Reset form
    setSender('');
    setRecipient('');
    setTitle('');
    setDetails('');
    setFile(null);
    if(fileInputRef.current) {
        fileInputRef.current.value = "";
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setFile(e.target.files[0]);
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="bg-white p-6 rounded-xl shadow-md sticky top-24"
    >
      <h2 className="text-2xl font-bold mb-6 text-slate-800">สร้างเอกสารส่งใหม่</h2>

      <div className="space-y-4">
        <div>
          <label htmlFor="sender" className="block text-sm font-medium text-slate-600 mb-1">
            จาก (ผสน.):
          </label>
          <input
            type="text"
            id="sender"
            value={sender}
            onChange={(e) => setSender(e.target.value)}
            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 transition"
            placeholder="ระบุชื่อ/แผนกผู้ส่ง"
            required
          />
        </div>

        <div>
          <label htmlFor="recipient" className="block text-sm font-medium text-slate-600 mb-1">
            ถึง (ผบร.):
          </label>
          <input
            type="text"
            id="recipient"
            value={recipient}
            onChange={(e) => setRecipient(e.target.value)}
            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 transition"
            placeholder="ระบุชื่อ/ตำแหน่งผู้รับ"
            required
          />
        </div>

        <div>
          <label htmlFor="title" className="block text-sm font-medium text-slate-600 mb-1">
            เรื่อง:
          </label>
          <input
            type="text"
            id="title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 transition"
            placeholder="หัวข้อเอกสาร"
            required
          />
        </div>

        <div>
          <label htmlFor="details" className="block text-sm font-medium text-slate-600 mb-1">
            รายละเอียด:
          </label>
          <textarea
            id="details"
            value={details}
            onChange={(e) => setDetails(e.target.value)}
            rows={4}
            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 transition"
            placeholder="บันทึกข้อความหรือรายละเอียดเพิ่มเติม"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-600 mb-2">แนบเอกสาร:</label>
          <div 
            className="flex justify-center items-center w-full px-6 py-8 border-2 border-slate-300 border-dashed rounded-lg cursor-pointer bg-slate-50 hover:bg-slate-100 transition"
            onClick={() => fileInputRef.current?.click()}
          >
            <div className="text-center">
              <UploadCloudIcon className="mx-auto h-12 w-12 text-slate-400" />
              <p className="mt-2 text-sm text-slate-600">
                <span className="font-semibold">คลิกเพื่ออัปโหลด</span> หรือลากไฟล์มาวาง
              </p>
              <p className="text-xs text-slate-500">PDF, DOCX, PPTX, XLSX</p>
              <input ref={fileInputRef} type="file" id="file-upload" className="hidden" onChange={handleFileChange} />
            </div>
          </div>
          {file && (
             <div className="mt-3 flex items-center justify-between bg-slate-100 p-2 rounded-lg">
                <div className="flex items-center gap-2 overflow-hidden">
                    <PaperclipIcon className="h-5 w-5 text-slate-500 flex-shrink-0" />
                    <span className="text-sm text-slate-700 truncate">{file.name}</span>
                </div>
                <button
                    type="button"
                    onClick={() => { setFile(null); if(fileInputRef.current) fileInputRef.current.value = ""; }}
                    className="text-red-500 hover:text-red-700 font-bold text-xl flex-shrink-0">&times;</button>
            </div>
          )}
        </div>
      </div>

      <div className="mt-6">
        <button
          type="submit"
          className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white font-bold py-3 px-4 rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-transform duration-150 ease-in-out active:scale-95"
        >
          <SendIcon className="h-5 w-5" />
          ส่งเอกสาร
        </button>
      </div>
    </form>
  );
};

export default DocumentForm;

import React from 'react';
import { Document, DocumentStatus } from '../types';
import DocumentListItem from './DocumentListItem';
import { InboxIcon } from './icons';

interface DocumentListProps {
  documents: Document[];
  onUpdateStatus: (id: string, status: DocumentStatus) => void;
}

const DocumentList: React.FC<DocumentListProps> = ({ documents, onUpdateStatus }) => {
  if (documents.length === 0) {
    return (
      <div className="text-center py-12">
        <InboxIcon className="mx-auto h-16 w-16 text-slate-300" />
        <p className="mt-4 text-slate-500">ยังไม่มีเอกสารในรายการ</p>
        <p className="text-sm text-slate-400">เมื่อมีการส่งเอกสารใหม่จะปรากฏที่นี่</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {documents.map(doc => (
        <DocumentListItem key={doc.id} document={doc} onUpdateStatus={onUpdateStatus} />
      ))}
    </div>
  );
};

export default DocumentList;

import React from 'react';
import { Document, DocumentStatus } from '../types';
import StatusBadge from './StatusBadge';
import { UserIcon, FileTextIcon, CalendarIcon, CheckCircleIcon, XCircleIcon } from './icons';

interface DocumentListItemProps {
  document: Document;
  onUpdateStatus: (id: string, status: DocumentStatus) => void;
}

const DocumentListItem: React.FC<DocumentListItemProps> = ({ document, onUpdateStatus }) => {
  const formatFileSize = (bytes: number): string => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const isActionable = document.status === DocumentStatus.InTransit || document.status === DocumentStatus.Pending;

  return (
    <div className="border border-slate-200 rounded-lg p-4 transition-shadow hover:shadow-lg bg-white">
      <div className="flex flex-col sm:flex-row justify-between sm:items-start gap-4">
        <div className="flex-grow">
          <div className="flex items-center gap-3 mb-2">
            <FileTextIcon className="h-5 w-5 text-slate-400" />
            <h3 className="text-lg font-semibold text-slate-800">{document.title}</h3>
          </div>
          <p className="text-sm text-slate-600 ml-8">{document.details}</p>
        </div>
        <div className="flex-shrink-0">
          <StatusBadge status={document.status} />
        </div>
      </div>

      <div className="border-t border-slate-200 my-4"></div>

      <div className="flex flex-wrap items-center justify-between gap-y-4 gap-x-6 text-sm text-slate-500">
        <div className="flex items-center gap-2" title="ผู้ส่ง">
          <UserIcon className="h-4 w-4" />
          <span>จาก: <span className="font-medium text-slate-700">{document.sender}</span></span>
        </div>
        <div className="flex items-center gap-2" title="ผู้รับ">
          <UserIcon className="h-4 w-4" />
          <span>ถึง: <span className="font-medium text-slate-700">{document.recipient}</span></span>
        </div>
        <div className="flex items-center gap-2" title="วันที่ส่ง">
          <CalendarIcon className="h-4 w-4" />
          <span>{document.submittedAt.toLocaleString('th-TH')}</span>
        </div>
      </div>

      <div className="mt-4 bg-slate-50 p-3 rounded-md flex items-center justify-between">
          <p className="text-sm text-slate-600">
              ไฟล์แนบ: <span className="font-medium text-blue-600 cursor-pointer hover:underline">{document.file.name}</span>
              <span className="text-slate-400 ml-2">({formatFileSize(document.file.size)})</span>
          </p>
      </div>

      {isActionable && (
        <div className="mt-4 pt-4 border-t border-slate-200 flex flex-col sm:flex-row gap-3">
          <p className="text-sm text-slate-500 self-center">สำหรับผู้รับ (ผบร.):</p>
          <div className="flex gap-3">
            <button
              onClick={() => onUpdateStatus(document.id, DocumentStatus.Delivered)}
              className="flex items-center gap-2 w-full sm:w-auto justify-center px-4 py-2 text-sm font-medium text-white bg-green-500 rounded-md hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition"
            >
              <CheckCircleIcon className="h-5 w-5" />
              รับทราบ / อนุมัติ
            </button>
            <button
              onClick={() => onUpdateStatus(document.id, DocumentStatus.Rejected)}
              className="flex items-center gap-2 w-full sm:w-auto justify-center px-4 py-2 text-sm font-medium text-white bg-red-500 rounded-md hover:bg-red-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 transition"
            >
              <XCircleIcon className="h-5 w-5" />
              ตีกลับ
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default DocumentListItem;

import React from 'react';
import { DocumentStatus } from '../types';

interface StatusBadgeProps {
  status: DocumentStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const getStatusColor = () => {
    switch (status) {
      case DocumentStatus.Pending:
        return 'bg-yellow-100 text-yellow-800 border-yellow-300';
      case DocumentStatus.InTransit:
        return 'bg-blue-100 text-blue-800 border-blue-300';
      case DocumentStatus.Delivered:
        return 'bg-green-100 text-green-800 border-green-300';
      case DocumentStatus.Rejected:
        return 'bg-red-100 text-red-800 border-red-300';
      default:
        return 'bg-slate-100 text-slate-800 border-slate-300';
    }
  };

  const getStatusDotColor = () => {
    switch (status) {
        case DocumentStatus.Pending:
            return 'bg-yellow-500';
        case DocumentStatus.InTransit:
            return 'bg-blue-500 animate-pulse';
        case DocumentStatus.Delivered:
            return 'bg-green-500';
        case DocumentStatus.Rejected:
            return 'bg-red-500';
        default:
            return 'bg-slate-500';
    }
  }

  return (
    <div className={`inline-flex items-center gap-2 px-3 py-1 text-xs font-semibold rounded-full border ${getStatusColor()}`}>
       <span className={`h-2 w-2 rounded-full ${getStatusDotColor()}`}></span>
      {status}
    </div>
  );
};

export default StatusBadge;

