export enum DocumentStatus {
  Pending = 'Pending / รอดำเนินการ',
  AwaitingApproval = 'Awaiting Approval / รอตรวจสอบ',
  Accepted = 'Accepted / อนุมัติแล้ว',
  Paid = 'Paid / จ่ายแล้ว',
  Rejected = 'Rejected / ตีกลับ',
}

export interface Document {
  id: string;
  title: string;
  sender: string;
  recipient: string;
  details: string;
  file: {
    name: string;
    size: number;
  };
  submittedAt: Date;
  status: DocumentStatus;
}

import React, { useState, useEffect } from 'react';
import { Document, DocumentStatus } from './types';
import DocumentForm from './components/DocumentForm';
import DocumentList from './components/DocumentList';
import { BriefcaseIcon, LogoIcon, UserCircleIcon, PlusCircleIcon } from './components/icons';

type UserRole = 'sender' | 'approver';

const App: React.FC = () => {
  const [documents, setDocuments] = useState<Document[]>([]);
  const [userRole, setUserRole] = useState<UserRole>('sender');
  const [showForm, setShowForm] = useState(false);

  useEffect(() => {
    // Load initial mock data
    const initialDocuments: Document[] = [
       {
        id: 'doc-1',
        title: 'Voucher #1023 - Marketing Campaign',
        sender: 'ฝ่ายการตลาด',
        recipient: 'ฝ่ายบัญชี',
        details: 'เบิกค่าใช้จ่ายสำหรับแคมเปญการตลาดออนไลน์เดือนที่ผ่านมา',
        file: { name: 'Marketing-Invoice-Oct.pdf', size: 150000 },
        submittedAt: new Date(Date.now() - 86400000 * 3),
        status: DocumentStatus.Paid,
      },
      {
        id: 'doc-2',
        title: 'Voucher #1024 - Office Supplies',
        sender: 'ฝ่ายธุรการ',
        recipient: 'ฝ่ายบัญชี',
        details: 'ขอเบิกค่าจัดซื้ออุปกรณ์สำนักงานประจำเดือน',
        file: { name: 'Office-Supplies-Nov.pdf', size: 95000 },
        submittedAt: new Date(Date.now() - 86400000),
        status: DocumentStatus.Accepted,
      },
      {
        id: 'doc-3',
        title: 'Voucher #1025 - IT Equipment',
        sender: 'ฝ่ายเทคโนโลยีสารสนเทศ',
        recipient: 'ฝ่ายบัญชี',
        details: 'เบิกเงินสำหรับจัดซื้อ Server เครื่องใหม่',
        file: { name: 'Server-Quote.pdf', size: 320000 },
        submittedAt: new Date(Date.now() - 3600000),
        status: DocumentStatus.AwaitingApproval,
      },
       {
        id: 'doc-4',
        title: 'Voucher #1026 - Travel Expenses',
        sender: 'ฝ่ายขาย',
        recipient: 'ฝ่ายบัญชี',
        details: 'ค่าเดินทางและที่พักของทีมขาย เอกสารแนบไม่ครบถ้วน',
        file: { name: 'Travel-Expenses-Q4.pdf', size: 980000 },
        submittedAt: new Date(Date.now() - 172800000),
        status: DocumentStatus.Rejected,
      },
      {
        id: 'doc-5',
        title: 'Voucher #1027 - Event Catering',
        sender: 'ฝ่ายบุคคล',
        recipient: 'ฝ่ายบัญชี',
        details: 'เบิกค่าอาหารสำหรับงานเลี้ยงบริษัทประจำปี',
        file: { name: 'Catering-Invoice.pdf', size: 120000 },
        submittedAt: new Date(),
        status: DocumentStatus.Pending,
      },
    ].sort((a, b) => b.submittedAt.getTime() - a.submittedAt.getTime());
    setDocuments(initialDocuments);
  }, []);

  const addDocument = (doc: Omit<Document, 'id' | 'submittedAt' | 'status'>) => {
    const newDoc: Document = {
      ...doc,
      id: `doc-${Date.now()}`,
      submittedAt: new Date(),
      status: DocumentStatus.Pending,
    };

    setDocuments(prevDocs => [newDoc, ...prevDocs]);
    setShowForm(false);

    setTimeout(() => {
      setDocuments(prevDocs => 
        prevDocs.map(d => 
          d.id === newDoc.id ? { ...d, status: DocumentStatus.AwaitingApproval } : d
        )
      );
    }, 2000);
  };

  const updateDocumentStatus = (id: string, status: DocumentStatus) => {
    setDocuments(prevDocs =>
      prevDocs.map(doc => (doc.id === id ? { ...doc, status } : doc))
    );
  };

  const RoleSwitcher = () => (
    <div className="flex bg-slate-200 rounded-full p-1 text-sm font-semibold">
        <button onClick={() => setUserRole('sender')} className={`px-4 py-1.5 rounded-full transition-colors ${userRole === 'sender' ? 'bg-white text-blue-600 shadow' : 'text-slate-600'}`}>
            Sender (ผสน.)
