                    <div>
                        <h1 className="text-lg font-bold text-slate-800">Document Tracking</h1>
                        <p className="text-xs text-slate-500">ระบบติดตามเอกสาร</p>
                    </div>
                </div>
                <div className="hidden sm:block">
                    <RoleSwitcher />
                </div>
            </div>
             <div className="sm:hidden mt-3 flex justify-center">
                <RoleSwitcher />
            </div>
        </div>
      </header>

      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        {userRole === 'sender' && (
            <div className="space-y-6">
                {showForm ? (
                    <DocumentForm onSubmit={addDocument} onCancel={() => setShowForm(false)} />
                ) : (
                    <button onClick={() => setShowForm(true)} className="w-full flex items-center justify-center gap-3 bg-blue-600 text-white font-bold py-4 px-4 rounded-xl hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-transform duration-150 ease-in-out active:scale-95 shadow-lg">
                        <PlusCircleIcon className="h-6 w-6" />
                        Upload Voucher / ส่งเอกสารเบิกจ่าย
                    </button>
                )}
                 <div className="bg-white p-4 sm:p-6 rounded-xl shadow-md">
                    <div className="flex items-center gap-3 mb-4">
                        <BriefcaseIcon className="h-6 w-6 text-blue-600" />
                        <h2 className="text-xl font-bold">Recent Vouchers / เอกสารล่าสุด</h2>
                    </div>
                    <DocumentList documents={documents} onUpdateStatus={updateDocumentStatus} userRole={userRole} />
                </div>
            </div>
        )}
         {userRole === 'approver' && (
            <div className="bg-white p-4 sm:p-6 rounded-xl shadow-md">
                <div className="flex items-center gap-3 mb-4">
                    <UserCircleIcon className="h-7 w-7 text-blue-600" />
                    <h2 className="text-xl font-bold">Awaiting Action / รออนุมัติ</h2>
                </div>
                <DocumentList documents={approverDocs} onUpdateStatus={updateDocumentStatus} userRole={userRole} />
