import React from 'react';
import { Document, DocumentStatus } from '../types';
import StatusBadge from './StatusBadge';
import { UserIcon, PdfIcon, CalendarIcon, CheckCircleIcon, XCircleIcon } from './icons';

interface DocumentListItemProps {
  document: Document;
  onUpdateStatus: (id: string, status: DocumentStatus) => void;
  userRole: 'sender' | 'approver';
}

const DocumentListItem: React.FC<DocumentListItemProps> = ({ document, onUpdateStatus, userRole }) => {
  const isApproverActionable = userRole === 'approver';

  const renderActions = () => {
    if (!isApproverActionable) return null;

    switch(document.status) {
        case DocumentStatus.AwaitingApproval:
            return (
                <div className="flex gap-3">
                    <button
                    onClick={() => onUpdateStatus(document.id, DocumentStatus.Accepted)}
                    className="flex-1 flex items-center gap-2 justify-center px-3 py-2 text-sm font-medium text-white bg-green-500 rounded-md hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition"
                    >
                        <CheckCircleIcon className="h-4 w-4" />
                        Accept
                    </button>
                    <button
                    onClick={() => onUpdateStatus(document.id, DocumentStatus.Rejected)}
                    className="flex-1 flex items-center gap-2 justify-center px-3 py-2 text-sm font-medium text-white bg-red-500 rounded-md hover:bg-red-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 transition"
                    >
                        <XCircleIcon className="h-4 w-4" />
                        Reject
                    </button>
                </div>
            );
        case DocumentStatus.Accepted:
            return (
                <button
                    onClick={() => onUpdateStatus(document.id, DocumentStatus.Paid)}
                    className="w-full flex items-center gap-2 justify-center px-3 py-2 text-sm font-medium text-white bg-blue-600 rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition"
                >
                    <CheckCircleIcon className="h-4 w-4" />
                    Mark as Paid / ยืนยันการจ่ายเงิน
                </button>
            );
        default:
            return null;
    }
  }

  return (
    <div className="border border-slate-200 rounded-lg p-4 transition-shadow hover:shadow-md bg-white">
        <div className="flex justify-between items-start gap-4">
            <div className="flex-grow">
                <h3 className="font-semibold text-slate-800 break-words">{document.title}</h3>
                <p className="text-sm text-slate-500">From: {document.sender}</p>
            </div>
            <div className="flex-shrink-0">
                <StatusBadge status={document.status} />
            </div>
        </div>

        <p className="text-sm text-slate-600 my-3">{document.details}</p>

        <div className="flex items-center gap-2 text-xs text-slate-400 mb-3">
            <CalendarIcon className="h-4 w-4" />
            <span>{document.submittedAt.toLocaleString('en-GB', { dateStyle: 'short', timeStyle: 'short' })}</span>
        </div>

        <div className="bg-slate-50 p-2 rounded-md flex items-center gap-2 cursor-pointer hover:bg-slate-100">
            <PdfIcon className="h-6 w-6 text-red-600 flex-shrink-0" />
            <p className="text-sm text-blue-700 font-medium truncate">{document.file.name}</p>
        </div>

        {renderActions() && (
            <div className="mt-4 pt-4 border-t border-slate-200">
                {renderActions()}
            </div>
        )}
    </div>
  );
};

export default DocumentListItem;

import React from 'react';
import { DocumentStatus } from '../types';

interface StatusBadgeProps {
  status: DocumentStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const getStatusColor = () => {
    switch (status) {
      case DocumentStatus.Pending:
        return 'bg-yellow-100 text-yellow-800 border-yellow-300';
      case DocumentStatus.AwaitingApproval:
        return 'bg-blue-100 text-blue-800 border-blue-300';
      case DocumentStatus.Accepted:
        return 'bg-indigo-100 text-indigo-800 border-indigo-300';
      case DocumentStatus.Paid:
        return 'bg-green-100 text-green-800 border-green-300';
      case DocumentStatus.Rejected:
        return 'bg-red-100 text-red-800 border-red-300';
      default:
        return 'bg-slate-100 text-slate-800 border-slate-300';
    }
  };

  const getStatusDotColor = () => {
    switch (status) {
        case DocumentStatus.Pending:
            return 'bg-yellow-500';
        case DocumentStatus.AwaitingApproval:
            return 'bg-blue-500 animate-pulse';
        case DocumentStatus.Accepted:
            return 'bg-indigo-500';
        case DocumentStatus.Paid:
            return 'bg-green-500';
        case DocumentStatus.Rejected:
            return 'bg-red-500';
        default:
            return 'bg-slate-500';
    }
  }

  return (
    <div className={`inline-flex items-center gap-2 px-3 py-1 text-xs font-semibold rounded-full border ${getStatusColor()}`}>
       <span className={`h-2 w-2 rounded-full ${getStatusDotColor()}`}></span>
      {status.split('/')[0].trim()}
    </div>
  );
};

export default StatusBadge;

