import React, { useState, useEffect } from 'react';
import { Document, DocumentStatus } from './types';
import DocumentForm from './components/DocumentForm';
import DocumentList from './components/DocumentList';
import SummaryCard from './components/SummaryCard';
import { BriefcaseIcon, LogoIcon, UserCircleIcon, PlusCircleIcon, ClockIcon, CreditCardIcon } from './components/icons';

type UserRole = 'sender' | 'approver';
type ApproverTab = 'review' | 'payment';

const App: React.FC = () => {
  const [documents, setDocuments] = useState<Document[]>([]);
  const [userRole, setUserRole] = useState<UserRole>('sender');
  const [approverTab, setApproverTab] = useState<ApproverTab>('review');
  const [showForm, setShowForm] = useState(false);

  useEffect(() => {
    const initialDocuments: Document[] = [
       { id: 'doc-1', title: 'Voucher #1023 - Marketing Campaign', sender: 'ฝ่ายการตลาด', recipient: 'ฝ่ายบัญชี', details: 'เบิกค่าใช้จ่ายสำหรับแคมเปญการตลาดออนไลน์เดือนที่ผ่านมา', file: { name: 'Marketing-Invoice-Oct.pdf', size: 150000 }, submittedAt: new Date(Date.now() - 86400000 * 3), status: DocumentStatus.Paid },
      { id: 'doc-2', title: 'Voucher #1024 - Office Supplies', sender: 'ฝ่ายธุรการ', recipient: 'ฝ่ายบัญชี', details: 'ขอเบิกค่าจัดซื้ออุปกรณ์สำนักงานประจำเดือน', file: { name: 'Office-Supplies-Nov.pdf', size: 95000 }, submittedAt: new Date(Date.now() - 86400000), status: DocumentStatus.Accepted },
      { id: 'doc-3', title: 'Voucher #1025 - IT Equipment', sender: 'ฝ่ายเทคโนโลยีสารสนเทศ', recipient: 'ฝ่ายบัญชี', details: 'เบิกเงินสำหรับจัดซื้อ Server เครื่องใหม่', file: { name: 'Server-Quote.pdf', size: 320000 }, submittedAt: new Date(Date.now() - 3600000), status: DocumentStatus.AwaitingApproval },
      { id: 'doc-4', title: 'Voucher #1026 - Travel Expenses', sender: 'ฝ่ายขาย', recipient: 'ฝ่ายบัญชี', details: 'ค่าเดินทางและที่พักของทีมขาย เอกสารแนบไม่ครบถ้วน', file: { name: 'Travel-Expenses-Q4.pdf', size: 980000 }, submittedAt: new Date(Date.now() - 172800000), status: DocumentStatus.Rejected },
      { id: 'doc-5', title: 'Voucher #1027 - Event Catering', sender: 'ฝ่ายบุคคล', recipient: 'ฝ่ายบัญชี', details: 'เบิกค่าอาหารสำหรับงานเลี้ยงบริษัทประจำปี', file: { name: 'Catering-Invoice.pdf', size: 120000 }, submittedAt: new Date(), status: DocumentStatus.Pending },
    ].sort((a, b) => b.submittedAt.getTime() - a.submittedAt.getTime());
    setDocuments(initialDocuments);
  }, []);

  const addDocument = (doc: Omit<Document, 'id' | 'submittedAt' | 'status'>) => {
    const newDoc: Document = { ...doc, id: `doc-${Date.now()}`, submittedAt: new Date(), status: DocumentStatus.Pending };
    setDocuments(prevDocs => [newDoc, ...prevDocs]);
    setShowForm(false);
    setTimeout(() => {
      setDocuments(prevDocs => prevDocs.map(d => d.id === newDoc.id ? { ...d, status: DocumentStatus.AwaitingApproval } : d));
    }, 2000);
  };

  const updateDocumentStatus = (id: string, status: DocumentStatus) => {
    setDocuments(prevDocs => prevDocs.map(doc => (doc.id === id ? { ...doc, status } : doc)));
  };

  const RoleSwitcher = () => (
    <div className="flex bg-slate-200 rounded-full p-1 text-sm font-semibold">
        <button onClick={() => setUserRole('sender')} className={`px-4 py-1.5 rounded-full transition-colors ${userRole === 'sender' ? 'bg-white text-blue-600 shadow' : 'text-slate-600'}`}>Sender (ผสน.)</button>
        <button onClick={() => setUserRole('approver')} className={`px-4 py-1.5 rounded-full transition-colors ${userRole === 'approver' ? 'bg-white text-blue-600 shadow' : 'text-slate-600'}`}>Approver (ผบร.)</button>
    </div>
  );

  const docsAwaitingReview = documents.filter(doc => doc.status === DocumentStatus.AwaitingApproval);
  const docsAwaitingPayment = documents.filter(doc => doc.status === DocumentStatus.Accepted);

  const approverDocsToDisplay = approverTab === 'review' ? docsAwaitingReview : docsAwaitingPayment;

  return (
    <div className="min-h-screen bg-slate-100 text-slate-800">
      <header className="bg-white shadow-sm sticky top-0 z-10">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-3">
            <div className="flex items-center justify-between">
                 <div className="flex items-center gap-3"><LogoIcon className="h-9 w-9 text-blue-600" /><div><h1 className="text-lg font-bold text-slate-800">Document Tracking</h1><p className="text-xs text-slate-500">ระบบติดตามเอกสาร</p></div></div>
                <div className="hidden sm:block"><RoleSwitcher /></div>
            </div>
            <div className="sm:hidden mt-3 flex justify-center"><RoleSwitcher /></div>
        </div>
      </header>

      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        {userRole === 'sender' && (
            <div className="space-y-6">
                {showForm ? <DocumentForm onSubmit={addDocument} onCancel={() => setShowForm(false)} />
                : <button onClick={() => setShowForm(true)} className="w-full flex items-center justify-center gap-3 bg-blue-600 text-white font-bold py-4 px-4 rounded-xl hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-transform duration-150 ease-in-out active:scale-95 shadow-lg"><PlusCircleIcon className="h-6 w-6" />[ + ส่งใบสำคัญจ่ายใหม่ ]</button>}
                <div className="bg-white p-4 sm:p-6 rounded-xl shadow-md"><div className="flex items-center gap-3 mb-4"><BriefcaseIcon className="h-6 w-6 text-blue-600" /><h2 className="text-xl font-bold">Document History / ประวัติเอกสาร</h2></div><DocumentList documents={documents} onUpdateStatus={updateDocumentStatus} userRole={userRole} /></div>
            </div>
        )}
         {userRole === 'approver' && (
            <div className="space-y-6">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <SummaryCard title="เอกสารรอตรวจ" count={docsAwaitingReview.length} icon={<ClockIcon />} />
                    <SummaryCard title="รอจ่ายเงิน" count={docsAwaitingPayment.length} icon={<CreditCardIcon />} />
                </div>
                <div className="bg-white p-4 sm:p-6 rounded-xl shadow-md">
                    <div className="border-b border-slate-200 mb-4">
                        <nav className="-mb-px flex gap-6" aria-label="Tabs">
                             <button onClick={() => setApproverTab('review')} className={`shrink-0 border-b-2 px-1 pb-4 text-sm font-medium ${approverTab === 'review' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:border-slate-300 hover:text-slate-700'}`}>Awaiting Review ({docsAwaitingReview.length})</button>
                             <button onClick={() => setApproverTab('payment')} className={`shrink-0 border-b-2 px-1 pb-4 text-sm font-medium ${approverTab === 'payment' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:border-slate-300 hover:text-slate-700'}`}>Awaiting Payment ({docsAwaitingPayment.length})</button>
                        </nav>
                    </div>
                    <DocumentList documents={approverDocsToDisplay} onUpdateStatus={updateDocumentStatus} userRole={userRole} />
                </div>
            </div>
         )}
      </main>

      <footer className="text-center py-6 mt-8 text-sm text-slate-500"><p>&copy; {new Date().getFullYear()} Document Tracking System. All rights reserved.</p></footer>
    </div>
  );
};

export default App;

import React from 'react';
import { DocumentStatus } from '../types';

interface StatusBadgeProps {
  status: DocumentStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const getStatusColor = () => {
    switch (status) {
      case DocumentStatus.Pending:
        return 'bg-yellow-100 text-yellow-800 border-yellow-300'; // Yellow
      case DocumentStatus.AwaitingApproval:
        return 'bg-sky-100 text-sky-800 border-sky-300'; // Bright Blue
      case DocumentStatus.Accepted:
        return 'bg-indigo-100 text-indigo-800 border-indigo-300'; // Indigo/Blue
      case DocumentStatus.Paid:
        return 'bg-green-100 text-green-800 border-green-300'; // Green
      case DocumentStatus.Rejected:
        return 'bg-red-100 text-red-800 border-red-300';
      default:
        return 'bg-slate-100 text-slate-800 border-slate-300';
    }
  };

  const getStatusDotColor = () => {
    switch (status) {
        case DocumentStatus.Pending:
            return 'bg-yellow-500'; // Yellow
        case DocumentStatus.AwaitingApproval:
            return 'bg-sky-500 animate-pulse'; // Bright Blue
        case DocumentStatus.Accepted:
            return 'bg-indigo-500'; // Indigo/Blue
        case DocumentStatus.Paid:
            return 'bg-green-500'; // Green
        case DocumentStatus.Rejected:
            return 'bg-red-500';
        default:
            return 'bg-slate-500';
    }
  }

  return (
    <div className={`inline-flex items-center gap-2 px-3 py-1 text-xs font-semibold rounded-full border ${getStatusColor()}`}>
       <span className={`h-2 w-2 rounded-full ${getStatusDotColor()}`}></span>
      {status.split('/')[0].trim()}
    </div>
  );
};

export default StatusBadge;

